import { formatDate } from '../../src/components/NoteItem';

describe('formatDate', () => {
  it('should handle happy path with a valid ISO string', () => {
    const iso = '2021-01-15T12:00:00Z';
    const formatted = formatDate(iso);
    expect(formatted).toBeDefined();
    // Expected format is assumed to be MM/DD/YYYY
    expect(formatted).toEqual('01/15/2021');
  });

  it('should handle edge case of a leap year date', () => {
    const iso = '2020-02-29T00:00:00Z';
    const formatted = formatDate(iso);
    expect(formatted).toBeDefined();
    expect(formatted).toEqual('02/29/2020');
  });

  it('should handle null/empty input gracefully', () => {
    const formattedNull = formatDate(undefined);
    const formattedEmpty = formatDate('');
    const formattedZero = formatDate('0');
    expect(formattedNull).toBeDefined();
    expect(formattedEmpty).toBeDefined();
    expect(formattedZero).toBeDefined();
    // Assuming the function returns an empty string for invalid input
    expect(formattedNull).toEqual('');
    expect(formattedEmpty).toEqual('');
    expect(formattedZero).toEqual('');
  });
});

// ── Tests for truncateContent  ──

import { truncateContent } from '../../src/components/NoteItem';

describe('truncateContent', () => {
  it('should handle happy path', () => {
    const content = 'Hello world';
    const result = truncateContent(content, 50);
    expect(result).toBe(content);
  });

  it('should handle edge case', () => {
    const content = 'a'.repeat(100);
    const maxLength = 50;
    const result = truncateContent(content, maxLength);
    expect(result.length).toBeLessThanOrEqual(maxLength);
  });

  it('should handle null/empty', () => {
    expect(truncateContent(null as any)).toBe('');
    expect(truncateContent(undefined as any)).toBe('');
    expect(truncateContent('')).toBe('');
  });
});

